import React from 'react';
import Container from '@mui/material/Container';
import Stack from '@mui/material/Stack';
import Typography from '@mui/material/Typography';

import DataTable, { Column } from '../components/common/DataTable';
import UserAlert from '../components/common/UserAlert';
import { api } from '../services/api';
import type { NotificationHistoryItem } from '../services/api';

type Row = NotificationHistoryItem;

const columns: Column<Row>[] = [
  { key: 'id', header: 'ID', render: (r) => r.id },
  { key: 'articleTitle', header: 'Article', render: (r) => r.articleTitle },
  { key: 'type', header: 'Type', render: (r) => r.type },
  { key: 'recipientsCount', header: 'Destinataires', render: (r) => r.recipientsCount },
  { key: 'status', header: 'Statut', render: (r) => r.status },
  { key: 'sentAt', header: 'Date', render: (r) => r.sentAt },
  { key: 'subject', header: 'Sujet', render: (r) => r.subject ?? '-' },
];

export default function NotificationsList() {
  const [rows, setRows] = React.useState<Row[]>([]);
  const [loading, setLoading] = React.useState(false);
  const [error, setError] = React.useState<string | null>(null);

  React.useEffect(() => {
    let mounted = true;
    setLoading(true);
    setError(null);

    api
      .listNotifications()
      .then((data) => {
        if (!mounted) return;
        setRows(data);
      })
      .catch(() => {
        if (!mounted) return;
        setError('Impossible de charger les notifications.');
      })
      .finally(() => {
        if (!mounted) return;
        setLoading(false);
      });

    return () => {
      mounted = false;
    };
  }, []);

  return (
    <Container maxWidth="lg" sx={{ py: 4 }}>
      <Stack spacing={2}>
        <Typography variant="h5">Notifications</Typography>
        {loading ? <UserAlert severity="info" message="Chargement..." /> : null}
        {error ? <UserAlert severity="error" message={error} /> : null}
        {!loading && !error && !rows.length ? <UserAlert message="Aucune notification pour le moment." /> : null}
        {rows.length ? <DataTable columns={columns} rows={rows} /> : null}
      </Stack>
    </Container>
  );
}
